const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const chatId = $('Captura Mensagem').first().json.chatId;
  const originalText = $('Captura Mensagem').first().json.originalText || '';
  let queue = '';

  try {
    const llmResponse = data.choices[0].message.content.trim();
    const cleaned = llmResponse.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
    if (cleaned && cleaned !== 'ERRO') {
      queue = cleaned;
    }
  } catch (e) {
    // LLM falhou, usa fallback
  }

  // Fallback determinístico
  if (!queue) {
    queue = originalText.trim();
  }

  results.push({
    json: { queue, chatId, originalText }
  });
}

return results;

