const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const chatId = $('Processa Resposta LLM').first().json.chatId;
  let message = '';

  try {
    const llmResponse = data.choices[0].message.content.trim();
    const cleaned = llmResponse.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
    if (cleaned) {
      message = cleaned;
    }
  } catch (e) {
    // LLM falhou
  }

  // Fallback determinístico
  if (!message) {
    const weather = $('Resposta Válida?').first().json;
    const cidade = weather.name || 'Desconhecida';
    const temp = Math.round(weather.main.temp);
    const desc = weather.weather[0].description || '';
    message = `🌤️ A temperatura em ${cidade} é de ${temp}°C.\nCondição: ${desc}.`;
  }

  results.push({
    json: { chatId, message }
  });
}

return results;

